static int waas_prepare_json_request(
    cJSON *request_json,
    const char *path,
    waas_prepared_request *prepared_request,
    waas_error *error
) {
    int rc = -1;
    char *request_body = NULL;
    waas_prepared_request prepared;
    waas_prepared_request_init(&prepared);

    if (!request_json || !path || !prepared_request) {
        waas_set_error(error, 0, 0, "ClientError", "request_json, path and prepared_request must be non-NULL", NULL);
        goto fail;
    }

    request_body = waas_cjson_print_dup(request_json);
    if (!request_body) {
        waas_set_error(error, 0, 0, "EncodeError", "failed to print request JSON", NULL);
        goto fail;
    }

    prepared.http_method = waas_strdup("POST");
    prepared.path = waas_strdup(path);
    prepared.content_type = waas_strdup("application/json");
    if (!prepared.http_method || !prepared.path || !prepared.content_type) {
        waas_set_error(error, 0, 0, "EncodeError", "failed to allocate prepared request metadata", NULL);
        goto fail;
    }

    prepared.body = request_body;
    prepared.body_len = strlen(request_body);
    request_body = NULL;

    *prepared_request = prepared;
    memset(&prepared, 0, sizeof(prepared));
    rc = 0;

fail:
    waas_prepared_request_free(&prepared);
    free(request_body);
    return rc;
}

